const aiRaw = $input.first().json.output || '';
const formData = $('Extract Typeform Fields1').first().json;

console.log('Raw AI output:', aiRaw);

let parsed = null;

// Attempt 1: direct parse
try { parsed = JSON.parse(aiRaw.trim()); } catch(e) {}

// Attempt 2: strip markdown fences
if (!parsed) {
  try {
    const s = aiRaw.replace(/```json/gi,'').replace(/```/g,'').trim();
    parsed = JSON.parse(s);
  } catch(e) {}
}

// Attempt 3: extract JSON block
if (!parsed) {
  try {
    const m = aiRaw.match(/\{[\s\S]*\}/);
    if (m) parsed = JSON.parse(m[0]);
  } catch(e) {}
}

// Attempt 4: regex fallback
if (!parsed) {
  const s = aiRaw.match(/lead_score["'\s:]+(["']?)(High|Medium|Low)\1/i);
  const i = aiRaw.match(/intent["'\s:]+["']([^"'\n,}]{3,100})["']/);
  const t = aiRaw.match(/timeline["'\s:]+["']([^"'\n,}]{3,100})["']/);
  const n = aiRaw.match(/notes["'\s:]+["']([^"'\n,}]{3,300})["']/);
  parsed = {
    lead_score: s ? s[2] : 'Medium',
    intent:     i ? i[1].trim() : 'Needs review',
    timeline:   t ? t[1].trim() : 'Not specified',
    notes:      n ? n[1].trim() : 'Manual review required'
  };
}

// Ensure lead_score is exactly High / Medium / Low
const validScores = ['High', 'Medium', 'Low'];
if (!validScores.includes(parsed.lead_score)) {
  parsed.lead_score = 'Medium';
}

console.log('Final parsed:', parsed);

return [{
  json: {
    full_name:     formData.name     || '',
    email:         formData.email    || '',
    phone:         formData.phone    || '',
    property_type: formData.property_type || '',
    purpose:       formData.purpose  || '',
    location:      formData.location || '',
    budget:        formData.budget   || '',
    requirements:  formData.requirements || '',
    submit_date:   formData.submit_date  || new Date().toISOString(),
    lead_score:    parsed.lead_score,
    intent:        parsed.intent  || '',
    timeline:      parsed.timeline || '',
    notes:         parsed.notes   || ''
  }
}];

