// ============================================================
// EXACT TYPEFORM FIELD EXTRACTOR
// Based on confirmed payload with exact field refs
// ============================================================

const input = $input.first().json;

// Typeform sends data inside form_response
const fr = input.body?.form_response || input.form_response || input.body || input;
const answers = fr.answers || [];

console.log('Total answers received:', answers.length);
console.log('Raw answers:', JSON.stringify(answers));

// Known field refs from your form
const REF_NAME        = '12829b05-575d-4c31-9569-79ddd0d9f2c2';
const REF_PHONE       = 'afd6483f-643d-4656-8e9d-d343c3745356';
const REF_EMAIL       = 'ebf62b12-c7f5-437f-aefd-848d645794cc';
const REF_PROP_TYPE   = 'eebd1c48-17b6-4139-a479-c6426b0fd968';
const REF_PURPOSE     = '9bd9f234-e544-49ae-b8a7-db3ed0b7764e';
const REF_LOCATION    = '44dc617b-f453-4ec3-8737-be40897c8505';
const REF_BUDGET      = '15471e0f-d172-4b2f-aaf1-c7f0799fc4bf';
const REF_REQUIREMENTS= '60ddbcf2-dd8b-490a-a0dd-f48bd629a30d';
const REF_CONSENT     = '5b0075bb-75fe-47e9-9b0c-ad4364d45ea9';

// Build a ref -> answer map
const refMap = {};
for (const a of answers) {
  const ref = a.field?.ref;
  if (ref) refMap[ref] = a;
}

// Extract value from answer object
function extract(ref) {
  const a = refMap[ref];
  if (!a) return '';
  if (a.type === 'text')         return a.text || '';
  if (a.type === 'email')        return a.email || '';
  if (a.type === 'phone_number') return a.phone_number || '';
  if (a.type === 'choice')       return a.choice?.label || '';
  if (a.type === 'choices')      return (a.choices?.labels || []).join(', ');
  if (a.type === 'boolean')      return a.boolean ? 'Yes' : 'No';
  if (a.type === 'number')       return String(a.number || '');
  return '';
}

const name         = extract(REF_NAME);
const phone        = extract(REF_PHONE);
const email        = extract(REF_EMAIL);
const propertyType = extract(REF_PROP_TYPE);
const purpose      = extract(REF_PURPOSE);
const location     = extract(REF_LOCATION);
const budget       = extract(REF_BUDGET);
const requirements = extract(REF_REQUIREMENTS);
const consent      = extract(REF_CONSENT);
const submitDate   = fr.submitted_at || new Date().toISOString();

console.log('Extracted:', { name, phone, email, propertyType, purpose, location, budget, requirements });

return [{
  json: {
    name,
    email,
    phone,
    property_type: propertyType,
    purpose,
    location,
    budget,
    requirements,
    consent,
    submit_date: submitDate
  }
}];
